import 'package:injectable/injectable.dart'; import '../service/device_service.dart'; import '../../../core/utils/app_logger.dart'; @injectable class FcmTokenUpdater { final DeviceService _svc; FcmTokenUpdater(this._svc); Future<void> update(String deviceId, String token) async { try { await _svc.updateFcmToken(deviceId, token); AppLogger.info('FCM token updated for $deviceId'); } catch (e) { AppLogger.warning('FCM token update failed: $e'); } } }